1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function typePremium(type: string, count: number): number {
18	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
19	    return BLOCK_PREMIUM;
20	  }
21	  return count * (BASE_PREMIUMS[type] ?? 0);
22	}
23	
24	function countByType(items: Array<{ type: string }>): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	
34	function cursedSurchargeTotal(items: Array<{ type: string; cursed?: boolean }>): number {
35	  let total = 0;
36	  for (const item of items) {
37	    if (item.cursed) {
38	      total += (BASE_PREMIUMS[item.type] ?? 0) * CURSED_SURCHARGE_RATE;
39	    }
40	  }
41	  return total;
42	}
43	
44	function calculateQuotePremium(items: Array<{ type: string; cursed?: boolean }>): number {
45	  const countsByType = countByType(items);
46	
47	  let policyBasePremium = 0;
48	  for (const [type, count] of Object.entries(countsByType)) {
49	    policyBasePremium += typePremium(type, count);
50	  }
51	
52	  const itemAdjustedTotal = policyBasePremium + cursedSurchargeTotal(items);
53	
54	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
55	  const rawPremium = itemAdjustedTotal + firstInsuranceSurcharge + PROCESSING_FEE;
56	  return Math.ceil(rawPremium);
57	}
58	
59	interface QuoteResult {
60	  premium: number;
61	}
62	
63	interface ScenarioOutcome {
64	  results: QuoteResult[];
65	}
66	
67	export function processScenario(scenario: {
68	  customer: { yearsWithMHPCO: number };
69	  steps: Array<{ op: string; items?: Array<{ type: string; cursed?: boolean }> }>;
70	}): ScenarioOutcome {
71	  return {
72	    results: scenario.steps.map((step) => ({
73	      premium: calculateQuotePremium(step.items ?? []),
74	    })),
75	  };
76	}
